sys_script.script:
(function executeRule(current, previous) {
    // Validate age >= 18
    var dob = current.getValue('dob');
    if (dob) {
        var birthDate = new GlideDateTime(dob);
        var now = new GlideDateTime();
        var diffYears = gs.dateDiff(birthDate.toString(), now.toString(), true);
        var ageInYears = Math.floor(parseInt(diffYears) / 365);
        if (ageInYears < 18) {
            gs.addErrorMessage('Donor must be at least 18 years old.');
            current.setAbortAction(true);
            return;
        }
    }

    // Validate weight >= 50
    var weight = parseFloat(current.getValue('weight'));
    if (weight < 50) {
        gs.addErrorMessage('Donor weight must be at least 50 kg.');
        current.setAbortAction(true);
        return;
    }
})(current, previous);
